Object.assign(controls, {
  sentence: 'DESIGN IS EVERYWHERE',
  fontSize: 28,
  lineHeight: 1.6,
  speed: 0.6,
  stagger: 0.35,
  textColor: '#1a1817',
  bgColor: '#0a0a0a',
  fontWeight: 'bold',
  waveShape: 'sine'
});

const sketch = (p) => {
  let font = 'Helvetica Neue, Helvetica, Arial, sans-serif';

  function oscillate(phase, shape) {
    const x = phase % (Math.PI * 2);
    switch (shape) {
      case 'triangle': {
        const t = (x / (Math.PI * 2));
        return t < 0.5 ? t * 2 : 2 - t * 2;
      }
      case 'square': {
        return (Math.tanh(6 * Math.sin(x)) + 1) / 2;
      }
      case 'sawtooth': {
        return (x / (Math.PI * 2));
      }
      case 'sawtooth_rev': {
        return 1 - (x / (Math.PI * 2));
      }
      case 'bounce': {
        return Math.abs(Math.sin(x));
      }
      case 'pulse': {
        const s = Math.sin(x);
        return (Math.tanh(12 * s) + 1) / 2;
      }
      case 'sine':
      default:
        return (Math.sin(x) + 1) / 2;
    }
  }

  function getCharWidths(chars, size) {
    p.textSize(size);
    return chars.map(c => p.textWidth(c));
  }

  p.setup = () => {
    p.createCanvas(p.windowWidth, p.windowHeight);
    p.textAlign(p.LEFT, p.TOP);
  };

  p.draw = () => {
    p.background(controls.bgColor);

    const now = p.millis();
    const raw = (controls.sentence || ' ').trim().toUpperCase();
    const displaySentence = raw.length > 0 ? raw : ' ';
    const chars = displaySentence.split('');
    const n = chars.length;
    const t = now / 1000;
    const lineH = controls.fontSize * controls.lineHeight;
    const numRows = Math.ceil(p.height / lineH) + 2;
    const padding = controls.fontSize * 0.5;

    p.textFont(font);
    p.textStyle(controls.fontWeight === 'bold' ? p.BOLD : p.NORMAL);
    p.textSize(controls.fontSize);
    p.noStroke();
    p.fill(controls.textColor);

    const charWidths = getCharWidths(chars, controls.fontSize);
    const baseWidth = charWidths.reduce((a, b) => a + b, 0);
    const gaps = Math.max(n - 1, 1);
    const maxExtra = Math.max(0, (p.width - padding * 2 - baseWidth) / gaps);

    for (let i = 0; i < numRows; i++) {
      const phase = t * controls.speed + i * controls.stagger;
      const norm = oscillate(phase, controls.waveShape);
      const extra = norm * maxExtra;
      const y = (i - 1) * lineH;

      let x = padding;
      for (let j = 0; j < n; j++) {
        p.text(chars[j], x, y);
        x += charWidths[j] + (j < n - 1 ? extra : 0);
      }
    }
  };

  p.windowResized = () => {
    p.resizeCanvas(p.windowWidth, p.windowHeight);
  };
};

new p5(sketch);
